      if (used_k > 0) {
        used_k -= 1
        val upgraded_s = s * 2
        if (graph(u).exists(edge => edge(0) == v && edge(1) == upgraded_s)) {
          graph(u) -= Array(v, upgraded_s)
          graph(v) -= Array(u, upgraded_s)
        }
      }
    } else {
      break
    }
  }

  val root = find(0, parent)
  var connected = true
  for (i <- 0 until n.toInt) {
    if (find(i, parent) != root) {
      connected = false
      break
    }
  }

  if (connected) max_stability else -1
